import { css } from 'decantr/css';
import { Card } from 'decantr/components';

code.example:
function TokenInspector() {
  const { div, span, code } = tags;
  const tokens = {
    'Colors': [
      { variable: '--d-primary', computed: '#6366f1' },
      { variable: '--d-secondary', computed: '#8b5cf6' },
      { variable: '--d-bg', computed: '#09090b' },
      { variable: '--d-fg', computed: '#fafafa' }
    ],
    'Surfaces': [
      { variable: '--d-surface-0', computed: '#18181b' },
      { variable: '--d-surface-1', computed: '#27272a' },
      { variable: '--d-surface-2', computed: '#3f3f46' }
    ]
  };

  return div({ class: css('_flex _col _gap4 _p4') },
    ...Object.entries(tokens).map(([category, items]) =>
      div({ class: css('_flex _col _gap2') },
        span({ class: css('_heading5') }, category),
        div({ class: css('_grid _gc3 _gap3') },
          ...items.map(t =>
            Card({ class: css('_flex _aic _gap3 _p3') },
              div({ class: css('_w[40px] _h[40px] _r4 _b1'), style: `background:var(${t.variable})` }),
              div({ class: css('_flex _col') },
                code({ class: css('_textsm _fontmono') }, t.variable),
                span({ class: css('_textxs _fgmuted') }, t.computed)
              )
            )
          )
        )
      )
    )
  );
}
